import { getItem } from '../../../../items/item.js';
import { toUserItem } from '../../../../items/user.js';
import { toServerForms } from '../../../forms/form.js';
export const toServerItemCommunityComment = (sonolus, localize, comment, actions) => ({
    name: comment.name,
    author: localize(comment.author),
    authorUser: comment.authorUser
        ? toUserItem(sonolus, localize, getItem(sonolus.user.items, comment.authorUser, `Comment/${comment.name}`, '.authorUser'))
        : undefined,
    time: comment.time,
    content: localize(comment.content),
    actions: toServerForms(localize, comment.actions, actions),
});
